import { describe, expect, it } from 'vitest';
import { buildAeonMonitor } from './aeon-monitor-build.js';

describe('aeon-monitor-build', () => {
  it('returns spawn failure envelope when cwd is invalid', async () => {
    const r = await buildAeonMonitor('/path/that/does/not/exist');
    expect(r.ok).toBe(false);
    expect(r.code).toBe('SPAWN_FAILED');
    expect(r.exitCode).toBeNull();
    expect(typeof r.message).toBe('string');
  });

  it('returns timeout envelope when timeout is too small', async () => {
    const r = await buildAeonMonitor(process.cwd(), { timeoutMs: 1_000 });
    // This may finish quickly on some hosts, so assert envelope shape either way.
    expect(typeof r.ok).toBe('boolean');
    expect(typeof r.code).toBe('string');
    expect(typeof r.timedOut).toBe('boolean');
    if (r.timedOut) {
      expect(r.code).toBe('BUILD_TIMEOUT');
    }
  });
});
